    #[allow(non_snake_case)]
    fn verify_layout_UNamingTokensEditableText() {
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText, filter_args),
            1736usize, "filter_args"
        );
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText, b_is_multiline),
            1761usize, "b_is_multiline"
        );
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText,
            b_display_token_icon), 1762usize, "b_display_token_icon"
        );
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText,
            b_display_error_message), 1763usize, "b_display_error_message"
        );
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText,
            b_display_border_image), 1764usize, "b_display_border_image"
        );
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText, argument_style),
            1776usize, "argument_style"
        );
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText, background_color),
            2624usize, "background_color"
        );
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText,
            b_can_display_resolved_text), 2644usize, "b_can_display_resolved_text"
        );
        assert_eq!(
            std::mem::offset_of!(crate
            ::bindings::naming_tokens_ui::UNamingTokensEditableText, contexts),
            2704usize, "contexts"
        );
    }
